func TestSplitResources(t *testing.T) {
	cases := []struct {
		in  string
		def string
		out []string
	}{
		{"photos,videos", "photos", []string{"photos", "videos"}},
		{"", "photos", []string{"photos"}},
		{" photos , ", "x", []string{"photos"}},
	}
	for _, tc := range cases {
		got := splitResources(tc.in, tc.def)
		if strings.Join(got, ",") != strings.Join(tc.out, ",") {
			t.Errorf("splitResources(%q,%q) = %v, want %v", tc.in, tc.def, got, tc.out)
		}
	}
}
